```python
# admin.py
from django.contrib import admin
from . import models
from django.urls import reverse
from django.utils.html import format_html


def html_tag_a(href, content):
    return '<a href="%s">%s</a>' % (href, content)


class SomeModelAdmin(admin.ModelAdmin):
    readonly_fields = [
        'links'
    ]

    def links(self, obj):
        url_to_xxx_list = reverse(
            'admin:%s_%s_changelist' % (
                obj._meta.app_label,
                models.XxxModel._meta.model_name
            )
        )
        return format_html(
            ' / '.join([
                html_tag_a(
                    url_to_xxx_list + '?foreign1__id__exact=' + str(obj.pk),
                    'f1'
                ),
                html_tag_a(
                    url_to_xxx_list + '?foreign2__id__exact=' + str(obj.pk),
                    'f2'
                )
            ])
        )
admin.site.register(models.SomeModel, SomeModelAdmin)
```
