replace = {
    0x07 : "&#x2407;", #escape BEL
    0x1a : "&#xfffd;" # EOF
}

def clean(x):
    new = []
    for c in list(x):
        o= ord(c)
        if o in replace:
            r = replace[o]
            new.append(r)
        else:
            new.append(c)
    return "".join(new)

